import java.util.Arrays;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Sort edges by time in ascending order
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        // Initialize Union-Find data structure
        UnionFind uf = new UnionFind((int) n);

        long result = 0;

        // Iterate through each edge
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long time = edge[2];

            // Union the nodes
            uf.union((int) u, (int) v);

            // Check if the number of connected components is at least k
            if (uf.getComponentsCount() >= k) {
                result = time;
                break;
            }
        }

        return result;
    }

    static class UnionFind {
        private int[] parent;
        private int[] rank;
        private int componentsCount;

        public UnionFind(int n) {
            this.parent = new int[n];
            this.rank = new int[n];
            this.componentsCount = n;

            for (int i = 0; i < n; i++) {
                this.parent[i] = i;
            }
        }

        public int find(int x) {
            if (this.parent[x] != x) {
                this.parent[x] = find(this.parent[x]);
            }
            return this.parent[x];
        }

        public void union(int x, int y) {
            int xRoot = find(x);
            int yRoot = find(y);

            if (xRoot == yRoot) return;

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] == this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }

            this.componentsCount--;
        }

        public int getComponentsCount() {
            return this.componentsCount;
        }
    }
}
